// Combinar resultados de los 4 detectores que convergen en este nodo.
// $input.all() recoge automáticamente los items de las 4 ramas upstream.
const todas = $input.all();

if (todas.length === 0) return [{ json: { sin_alertas: true } }];

return todas.map(item => ({ json: { ...item.json } }));

