// El AI Agent reemplaza el JSON con su output, perdiendo los campos de la alerta original.
// Recuperamos la alerta cruzando con 'Combinar Resultados Detectores' (paired item) y
// fusionamos con la clasificación devuelta por el LLM.
const ia = $input.first().json;
const alerta = $('Combinar Resultados Detectores').item.json;
const rawText = ia.output || ia.text || ia.content || '';

let iaJson = {};
try {
  const match = String(rawText).match(/\{[\s\S]*\}/);
  if (match) iaJson = JSON.parse(match[0]);
} catch (e) {}

return [{
  json: {
    ...alerta,
    causa_raiz_sugerida: iaJson.causa_raiz || 'Clasificación pendiente',
    narrativa_ia: iaJson.narrativa || alerta.narrativa_corta
  }
}];

const alerta = $json;
const ia = $('Enriquecer Alerta con IA').first().json;

const sevIcon = alerta.severidad === 'critica' ? '🚨' : '⚠️';
const channel = alerta.severidad === 'critica' ? 'C0AVCTBV665' : 'C0AUWJ91V1T';
const nombre = alerta.contratista_nombre || alerta.contratista_id;
const narrativa = ia.narrativa_ia || alerta.narrativa_corta || '';
const causa = ia.causa_raiz_sugerida || 'N/D';

const slack_blocks = [
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `${sevIcon} *[${alerta.codigo_alerta}] ${String(alerta.severidad).toUpperCase()} — ${nombre}*\n${narrativa}\n\n_Causa raíz sugerida (IA): ${causa}_` }
  },
  {
    type: 'actions',
    elements: [
      { type: 'button', text: { type: 'plain_text', text: 'Aprobar' }, action_id: `aprobar_${alerta.id}`, style: 'primary', value: `aprobar_${alerta.id}` },
      { type: 'button', text: { type: 'plain_text', text: 'Falso positivo' }, action_id: `fp_${alerta.id}`, style: 'danger', value: `fp_${alerta.id}` }
    ]
  }
];

return [{ json: { channel, slack_blocks, codigo_alerta: alerta.codigo_alerta } }];
